// // This module performs a 4-bit barrel shifter that shifts the input bits to the right or left based on a control signal. The right shift appends 0s, while the left shift also appends 0s. The control signal determines the direction of the shift and the amount of shift (0 to 3 bits).
module barrel_shifter(  
    input [3:0] data_in,  
    input [1:0] shift_amount,  
    input direction, // 0 for left shift, 1 for right shift  
    output [3:0] data_out  
);  
    assign data_out = (direction == 0) ? (data_in << shift_amount) : (data_in >> shift_amount);  
endmodule
